UPDATE d_program
SET program_status = 0,
    edit_time = #{now}
WHERE id = #{programId}
  AND status = 1
  AND program_status = 1

mapper.select:
SELECT FROM d_program WHERE status = 1 AND program_status = 1
AND title LIKE CONCAT('%', #{keyword}, '%')
AND (program_category_id = #{categoryId} OR parent_program_category_id = #{categoryId})
AND area_id = #{areaId}
ORDER BY high_heat DESC, issue_time DESC, id DESC LIMIT #{limit} OFFSET #{offset}

SELECT tc.program_id, MIN(tc.price) AS min_price, MAX(tc.price) AS max_price FROM d_ticket_category tc WHERE tc.status = 1 AND tc.program_id IN
#{programId}
GROUP BY tc.program_id

mapper.update:
UPDATE d_ticket_category
SET price = #{price},
    edit_time = #{now}
WHERE id = #{ticketCategoryId}
  AND program_id = #{programId}
  AND status = 1

UPDATE d_ticket_category
SET remain_number = remain_number - #{quantity},
    edit_time = #{now}
WHERE id = #{ticketCategoryId}
  AND program_id = #{programId}
  AND status = 1
  AND remain_number >= #{quantity}

UPDATE d_ticket_category
SET remain_number = LEAST(total_number, remain_number + #{quantity}),
    edit_time = #{now}
WHERE id = #{ticketCategoryId}
  AND program_id = #{programId}
  AND status = 1

UPDATE d_seat
SET sell_status = #{toStatus},
    edit_time = #{now}
WHERE id = #{seatId}
  AND program_id = #{programId}
  AND ticket_category_id = #{ticketCategoryId}
  AND sell_status = #{fromStatus}
  AND status = 1
